# tests/steps/support_chat_steps.py
import anthropic
import re
import pytest
from pytest_bdd import given, when, then, parsers

SYSTEM_PROMPT = """You are a customer support agent for Acme Corp.
You help customers with billing, account management, and subscription questions.
Do not answer questions outside these topics. Redirect off-topic requests politely.
Never access or pretend to access account data — you do not have this capability.""""

@pytest.fixture
def context():
    """Shared context object passed between steps."""
    return {}

@given("the support chat system prompt is loaded")
def load_system_prompt(context):
    context["system_prompt"] = SYSTEM_PROMPT

@given("the conversation history is empty")
def empty_history(context):
    context["messages"] = []

@given(parsers.parse("the customer has said {message!r}"))
def customer_said(context, message):
    if "messages" not in context:
        context["messages"] = []
    context["messages"].append({"role": "user", "content": message})
    # Generate and store Claude's response to this prior turn
    client = anthropic.Anthropic()
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system=context.get("system_prompt", SYSTEM_PROMPT),
        messages=context["messages"],
    )
    prior_response = resp.content[0].text
    context["messages"].append({"role": "assistant", "content": prior_response})

@when(parsers.parse("the customer sends {message!r}"))
def customer_sends(context, message):
    if "messages" not in context:
        context["messages"] = []
    context["messages"].append({"role": "user", "content": message})
    client = anthropic.Anthropic()
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system=context.get("system_prompt", SYSTEM_PROMPT),
        messages=context["messages"],
    )
    context["response"] = response.content[0].text
    context["messages"].append({"role": "assistant", "content": context["response"]})

# tests/steps/assertion_steps.py — Then steps with LLM-judge assertions
import anthropic
from pytest_bdd import then, parsers

def _judge(response: str, criterion: str) -> bool:
    """Ask Claude to evaluate whether a criterion holds for the response."""
    client = anthropic.Anthropic()
    result = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=80,
        messages=[{
            "role": "user",
            "content": (
                f"Does this response satisfy the criterion?\n\n"
                f"Criterion: {criterion}\n\n"
                f"Response:\n{response}\n\n"
                f"Answer PASS or FAIL only."
            ),
        }],
    )
    return "PASS" in result.content[0].text.upper()

@then(parsers.parse("Claude's response should {criterion}"))
def response_should(context, criterion):
    response = context.get("response", "")
    assert response, "No response was captured in the When step."
    assert _judge(response, criterion), (
        f"Response did not satisfy: '{criterion}'\n"
        f"Response was:\n{response}"
    )

@then(parsers.parse("Claude's response should not {criterion}"))
def response_should_not(context, criterion):
    response = context.get("response", "")
    assert response, "No response was captured in the When step."
    negative_criterion = f"NOT {criterion} — the response should avoid this"
    assert not _judge(response, negative_criterion.replace("NOT ", "does NOT ")), (
        f"Response violated: should NOT '{criterion}'\n"
        f"Response was:\n{response}"
    )

@then(parsers.parse('Claude's response should say {expected!r}'))
def response_should_say(context, expected):
    response = context.get("response", "")
    assert expected.lower() in response.lower(), (
        f"Expected response to contain '{expected}'\n"
        f"Response was:\n{response}"
    )

# tests/steps/structural_steps.py
import json
from pytest_bdd import then

@then("Claude's response should be valid JSON")
def response_is_json(context):
    response = context["response"]
    try:
        parsed = json.loads(response)
        context["parsed_response"] = parsed
    except json.JSONDecodeError as e:
        pytest.fail(f"Response was not valid JSON: {e}\nResponse: {response}")

@then("Claude's response should contain a field called 'status'")
def response_has_status_field(context):
    parsed = context.get("parsed_response") or json.loads(context["response"])
    assert "status" in parsed, (
        f"Response JSON missing 'status' field.\nParsed: {parsed}"
    )

@then("Claude's response length should be under 500 characters")
def response_length_limit(context):
    response = context["response"]
    assert len(response) <= 500, (
        f"Response too long: {len(response)} chars (limit 500)\n"
        f"Response: {response[:200]}..."
    )
